#define NUMBER_THREADS 256

// Assuming the following structs and global variables as in the original CUDA code environment:
typedef float fp;

typedef struct {
    int frame_no;
    fp* d_frame;
    int frame_rows;
    int frame_cols;
    int frame_elem;
    int no_frames;
