// The kernel translated to OpenMP
void kernel(params_common d_common, params_unique d_unique){
    int bx, tx;
    int thread_count = NUMBER_THREADS;

    #pragma omp parallel num_threads(thread_count)
    {
        int tid = omp_get_thread_num();
        bx = 0; // Assuming bx = 0 because in CUDA it was blockIdx.x, here single block
        tx = tid;

        int ei_new;
        fp* d_in;
        int rot_row;
        int rot_col;
        int in2_rowlow;
        int in2_collow;
        int ic;
        int jc;
        int jp1;
        int ja1, ja2;
        int ip1;
        int ia1, ia2;
        int ja, jb;
        int ia, ib;
        fp s;
        int i;
        int j;
        int row;
        int col;
        int ori_row;
        int ori_col;
        int position;
        fp sum;
        int pos_ori;
        fp temp;
        fp temp2;
        int location;
        int cent;
        int tMask_row; 
        int tMask_col;
        fp largest_value_current = 0;
        fp largest_value = 0;
        int largest_coordinate_current = 0;
        int largest_coordinate = 0;
        fp fin_max_val = 0;
        int fin_max_coo = 0;
        int largest_row;
        int largest_col;
        int offset_row;
        int offset_col;
        int pointer;
        int ori_pointer;
        int loc_pointer;

        if(d_common.frame_no == 0){
            d_in = &d_unique.d_T[d_unique.in_pointer];

            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_elem; ei_new++){
                row = (ei_new+1) % d_common.in_rows - 1;                                                
                col = (ei_new+1) / d_common.in_rows;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }

                ori_row = d_unique.d_Row[d_unique.point_no] - 25 + row - 1;
                ori_col = d_unique.d_Col[d_unique.point_no] - 25 + col - 1;
                ori_pointer = ori_col * d_common.frame_rows + ori_row;

                d_in[col * d_common.in_rows + row] = d_common.d_frame[ori_pointer];
            }

            #pragma omp single
            {
                pointer = d_unique.point_no * d_common.no_frames + d_common.frame_no;
                d_unique.d_tRowLoc[pointer] = d_unique.d_Row[d_unique.point_no];
                d_unique.d_tColLoc[pointer] = d_unique.d_Col[d_unique.point_no];
            }
        }

        if(d_common.frame_no != 0){

            in2_rowlow = d_unique.d_Row[d_unique.point_no] - d_common.sSize;
            in2_collow = d_unique.d_Col[d_unique.point_no] - d_common.sSize;

            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_rows - 1;                                                
                col = (ei_new+1) / d_common.in2_rows;
                if((ei_new+1) % d_common.in2_rows == 0){
                    row = d_common.in2_rows - 1;
                    col = col - 1;
                }

                ori_row = row + in2_rowlow - 1;
                ori_col = col + in2_collow - 1;
                d_unique.d_in2[ei_new] = d_common.d_frame[ori_col * d_common.frame_rows + ori_row];
            }

            #pragma omp barrier

            d_in = &d_unique.d_T[d_unique.in_pointer];

            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_elem; ei_new++){
                row = (ei_new+1) % d_common.in_rows - 1;                                                
                col = (ei_new+1) / d_common.in_rows;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }

                rot_row = (d_common.in_rows - 1) - row;
                rot_col = (d_common.in_rows - 1) - col;
                int idx = rot_col * d_common.in_rows + rot_row;
                d_unique.d_in_mod[col * d_common.in_rows + row] = d_in[idx];
            }

            #pragma omp barrier

            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_elem; ei_new++){
                int idx = ei_new;
                temp = d_unique.d_in_mod[idx];
                d_unique.d_in_sqr[idx] = temp * temp;
            }

            #pragma omp barrier

            // Convolution loop
            #pragma omp for collapse(2) schedule(static)
            for(col = 1; col <= d_common.conv_cols; col++){
                for(row = 1; row <= d_common.conv_rows; row++){
                    j = col + d_common.joffset;
                    jp1 = j + 1;
                    ja1 = (d_common.in2_cols < jp1) ? (jp1 - d_common.in2_cols) : 1;
                    ja2 = (d_common.in_cols < j) ? d_common.in_cols : j;
                    i = row + d_common.ioffset;
                    ip1 = i + 1;
                    ia1 = (d_common.in2_rows < ip1) ? (ip1 - d_common.in2_rows) : 1;
                    ia2 = (d_common.in_rows < i) ? d_common.in_rows : i;
                    s = 0;
                    for(ja = ja1; ja <= ja2; ja++){
                        jb = jp1 - ja;
                        for(ia = ia1; ia <= ia2; ia++){
                            ib = ip1 - ia;
                            s += d_unique.d_in_mod[d_common.in_rows*(ja-1)+ia-1] * d_unique.d_in2[d_common.in2_rows*(jb-1)+ib-1];
                        }
                    }
                    d_unique.d_conv[(col-1)*d_common.conv_rows+(row-1)] = s;
                }
            }

            #pragma omp barrier

            // Padding d_in2_pad
            #pragma omp for schedule(static)
            for(int idx = 0; idx < d_common.in2_pad_cumv_elem; idx++){
                row = (idx+1) % d_common.in2_pad_cumv_rows - 1;
                int col = (idx+1) / d_common.in2_pad_cumv_rows;
                if((idx+1) % d_common.in2_pad_cumv_rows == 0){
                    row = d_common.in2_pad_cumv_rows - 1;
                    col = col - 1;
                }
                if(row >= d_common.in2_pad_add_rows && row < d_common.in2_pad_add_rows + d_common.in2_rows &&
                   col >= d_common.in2_pad_add_cols && col < d_common.in2_pad_add_cols + d_common.in2_cols){
                    ori_row = row - d_common.in2_pad_add_rows;
                    ori_col = col - d_common.in2_pad_add_cols;
                    d_unique.d_in2_pad[idx] = d_unique.d_in2[ori_col * d_common.in2_rows + ori_row];
                }
                else{
                    d_unique.d_in2_pad[idx] = 0;
                }
            }

            #pragma omp barrier

            // Cumulative vertical sum over columns
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_pad_cumv_cols; ei_new++){
                pos_ori = ei_new * d_common.in2_pad_cumv_rows;
                sum = 0;
                for(position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position++){
                    d_unique.d_in2_pad[position] += sum;
                    sum = d_unique.d_in2_pad[position];
                }
            }

            #pragma omp barrier

            // Selection d_in2_pad_cumv_sel
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_pad_cumv_sel_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_pad_cumv_sel_rows - 1;
                col = (ei_new+1) / d_common.in2_pad_cumv_sel_rows;
                if((ei_new+1) % d_common.in2_pad_cumv_sel_rows == 0){
                    row = d_common.in2_pad_cumv_sel_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
                d_unique.d_in2_pad_cumv_sel[ei_new] = d_unique.d_in2_pad[ori_col * d_common.in2_pad_cumv_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub_cumh
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_sub_cumh_rows - 1;
                col = (ei_new+1) / d_common.in2_sub_cumh_rows;
                if((ei_new+1) % d_common.in2_sub_cumh_rows == 0){
                    row = d_common.in2_sub_cumh_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
                d_unique.d_in2_sub_cumh[ei_new] = d_unique.d_in2_pad[ori_col * d_common.in2_pad_cumv_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub_cumh difference
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_elem; ei_new++){
                d_unique.d_in2_sub_cumh[ei_new] = d_unique.d_in2_pad_cumv_sel[ei_new] - d_unique.d_in2_sub_cumh[ei_new];
            }

            #pragma omp barrier

            // Cumulative sum on d_in2_sub_cumh
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_rows; ei_new++){
                pos_ori = ei_new;
                sum = 0;
                for(position = pos_ori; position < pos_ori + d_common.in2_sub_cumh_elem; position += d_common.in2_sub_cumh_rows){
                    d_unique.d_in2_sub_cumh[position] += sum;
                    sum = d_unique.d_in2_sub_cumh[position];
                }
            }

            #pragma omp barrier

            // d_in2_sub_cumh_sel
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_sel_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_sub_cumh_sel_rows - 1;
                col = (ei_new+1) / d_common.in2_sub_cumh_sel_rows;
                if((ei_new+1) % d_common.in2_sub_cumh_sel_rows == 0){
                    row = d_common.in2_sub_cumh_sel_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
                d_unique.d_in2_sub_cumh_sel[ei_new] = d_unique.d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub2
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_sub2_rows - 1;
                col = (ei_new+1) / d_common.in2_sub2_rows;
                if((ei_new+1) % d_common.in2_sub2_rows == 0){
                    row = d_common.in2_sub2_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
                d_unique.d_in2_sub2[ei_new] = d_unique.d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub2 difference
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                d_unique.d_in2_sub2[ei_new] = d_unique.d_in2_sub_cumh_sel[ei_new] - d_unique.d_in2_sub2[ei_new];
            }

            #pragma omp barrier

            // d_in2_sqr calculation
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sqr_elem; ei_new++){
                temp = d_unique.d_in2[ei_new];
                d_unique.d_in2_sqr[ei_new] = temp * temp;
            }

            #pragma omp barrier

            // Padding d_in2_pad for d_in2_sqr
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_pad_cumv_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_pad_cumv_rows - 1;
                int col = (ei_new+1) / d_common.in2_pad_cumv_rows;
                if((ei_new+1) % d_common.in2_pad_cumv_rows == 0){
                    row = d_common.in2_pad_cumv_rows - 1;
                    col = col - 1;
                }
                if(row >= d_common.in2_pad_add_rows && row < d_common.in2_pad_add_rows + d_common.in2_sqr_rows &&
                   col >= d_common.in2_pad_add_cols && col < d_common.in2_pad_add_cols + d_common.in2_sqr_cols){
                    ori_row = row - d_common.in2_pad_add_rows;
                    ori_col = col - d_common.in2_pad_add_cols;
                    d_unique.d_in2_pad[ei_new] = d_unique.d_in2_sqr[ori_col * d_common.in2_sqr_rows + ori_row];
                }
                else{
                    d_unique.d_in2_pad[ei_new] = 0;
                }
            }

            #pragma omp barrier

            // Cumulative sum again on d_in2_pad
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_pad_cumv_cols; ei_new++){
                pos_ori = ei_new * d_common.in2_pad_cumv_rows;
                sum = 0;
                for(position = pos_ori; position < pos_ori + d_common.in2_pad_cumv_rows; position++){
                    d_unique.d_in2_pad[position] += sum;
                    sum = d_unique.d_in2_pad[position];
                }
            }

            #pragma omp barrier

            // d_in2_pad_cumv_sel again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_pad_cumv_sel_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_pad_cumv_sel_rows - 1;
                int col = (ei_new+1) / d_common.in2_pad_cumv_sel_rows;
                if((ei_new+1) % d_common.in2_pad_cumv_sel_rows == 0){
                    row = d_common.in2_pad_cumv_sel_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_pad_cumv_sel_rowlow - 1;
                ori_col = col + d_common.in2_pad_cumv_sel_collow - 1;
                d_unique.d_in2_pad_cumv_sel[ei_new] = d_unique.d_in2_pad[ori_col * d_common.in2_pad_cumv_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub_cumh again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_sub_cumh_rows - 1;
                int col = (ei_new+1) / d_common.in2_sub_cumh_rows;
                if((ei_new+1) % d_common.in2_sub_cumh_rows == 0){
                    row = d_common.in2_sub_cumh_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_pad_cumv_sel2_rowlow - 1;
                ori_col = col + d_common.in2_pad_cumv_sel2_collow - 1;
                d_unique.d_in2_sub_cumh[ei_new] = d_unique.d_in2_pad[ori_col * d_common.in2_pad_cumv_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub_cumh difference again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_elem; ei_new++){
                d_unique.d_in2_sub_cumh[ei_new] = d_unique.d_in2_pad_cumv_sel[ei_new] - d_unique.d_in2_sub_cumh[ei_new];
            }

            #pragma omp barrier

            // Cumulative sum on d_in2_sub_cumh again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_rows; ei_new++){
                pos_ori = ei_new;
                sum = 0;
                for(position = pos_ori; position < pos_ori + d_common.in2_sub_cumh_elem; position += d_common.in2_sub_cumh_rows){
                    d_unique.d_in2_sub_cumh[position] += sum;
                    sum = d_unique.d_in2_sub_cumh[position];
                }
            }

            #pragma omp barrier

            // d_in2_sub_cumh_sel again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub_cumh_sel_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_sub_cumh_sel_rows - 1;
                int col = (ei_new+1) / d_common.in2_sub_cumh_sel_rows;
                if((ei_new+1) % d_common.in2_sub_cumh_sel_rows == 0){
                    row = d_common.in2_sub_cumh_sel_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_sub_cumh_sel_rowlow - 1;
                ori_col = col + d_common.in2_sub_cumh_sel_collow - 1;
                d_unique.d_in2_sub_cumh_sel[ei_new] = d_unique.d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub2 again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                row = (ei_new+1) % d_common.in2_sub2_rows - 1;
                int col = (ei_new+1) / d_common.in2_sub2_rows;
                if((ei_new+1) % d_common.in2_sub2_rows == 0){
                    row = d_common.in2_sub2_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
                d_unique.d_in2_sqr_sub2[ei_new] = d_unique.d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

            #pragma omp barrier

            // d_in2_sub2 difference again
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                d_unique.d_in2_sqr_sub2[ei_new] = d_unique.d_in2_sub_cumh_sel[ei_new] - d_unique.d_in2_sqr_sub2[ei_new];
            }

            #pragma omp barrier

            // Normalize d_in2_sqr_sub2
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                temp = d_unique.d_in2_sub2[ei_new];
                temp2 = d_unique.d_in2_sqr_sub2[ei_new] - (temp * temp / d_common.in_elem);
                if(temp2 < 0){
                    temp2 = 0;
                }
                d_unique.d_in2_sqr_sub2[ei_new] = sqrt(temp2);
            }

            #pragma omp barrier

            // Calculate d_in_sqr
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_sqr_elem; ei_new++){
                temp = d_in[ei_new];
                d_unique.d_in_sqr[ei_new] = temp * temp;
            }

            #pragma omp barrier

            // Sum d_in per column
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_cols; ei_new++){
                sum = 0;
                for(i = 0; i < d_common.in_rows; i++){
                    sum += d_in[ei_new * d_common.in_rows + i];
                }
                d_unique.in_partial_sum[ei_new] = sum;
            }

            #pragma omp barrier

            // Sum d_in_sqr per row
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_sqr_rows; ei_new++){
                sum = 0;
                for(i = 0; i < d_common.in_sqr_cols; i++){
                    sum += d_unique.d_in_sqr[ei_new + d_common.in_sqr_rows * i];
                }
                d_unique.in_sqr_partial_sum[ei_new] = sum;
            }

            #pragma omp barrier

            fp in_final_sum = 0;
            fp in_sqr_final_sum = 0;

            #pragma omp single
            {
                for(i = 0; i < d_common.in_cols; i++){
                    in_final_sum += d_unique.in_partial_sum[i];
                }
            }

            #pragma omp barrier

            #pragma omp single
            {
                for(i = 0; i < d_common.in_sqr_cols; i++){
                    in_sqr_final_sum += d_unique.in_sqr_partial_sum[i];
                }
            }

            #pragma omp barrier

            fp mean = 0;
            fp mean_sqr = 0;
            fp variance = 0;
            fp deviation = 0;
            fp denomT = 0;

            #pragma omp single
            {
                mean = in_final_sum / d_common.in_elem;
                mean_sqr = mean * mean;
                variance = (in_sqr_final_sum / d_common.in_elem) - mean_sqr;
                deviation = sqrt(variance);
                denomT = sqrt((fp)(d_common.in_elem - 1)) * deviation;
            }

            #pragma omp barrier

            // Scale d_in2_sqr_sub2 by denomT
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                d_unique.d_in2_sqr_sub2[ei_new] *= denomT;
            }

            #pragma omp barrier

            // Adjust d_conv
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.conv_elem; ei_new++){
                d_unique.d_conv[ei_new] = d_unique.d_conv[ei_new] - d_unique.d_in2_sub2[ei_new] * in_final_sum / d_common.in_elem;
            }

            #pragma omp barrier

            // Final division on d_in2_sqr_sub2
            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++){
                d_unique.d_in2_sqr_sub2[ei_new] = d_unique.d_conv[ei_new] / d_unique.d_in2_sqr_sub2[ei_new];
            }

            #pragma omp barrier

            cent = d_common.sSize + d_common.tSize + 1;

            if (d_common.frame_no == 0) {
                tMask_row = cent + d_unique.d_Row[d_unique.point_no] - d_unique.d_Row[d_unique.point_no] - 1;
                tMask_col = cent + d_unique.d_Col[d_unique.point_no] - d_unique.d_Col[d_unique.point_no] - 1;
            }
            else {
                pointer = d_common.frame_no - 1 + d_unique.point_no * d_common.no_frames;
                tMask_row = cent + d_unique.d_tRowLoc[pointer] - d_unique.d_Row[d_unique.point_no] - 1;
                tMask_col = cent + d_unique.d_tColLoc[pointer] - d_unique.d_Col[d_unique.point_no] - 1;
            }

            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.tMask_elem; ei_new++){
                location = tMask_col * d_common.tMask_rows + tMask_row;
                d_unique.d_tMask[ei_new] = (ei_new == location) ? 1 : 0;
            }

            #pragma omp barrier

            // Convolution with mask
            #pragma omp for collapse(2) schedule(static)
            for(int ic = 1; ic <= d_common.mask_conv_rows; ic++){
                for(int jc = 1; jc <= d_common.mask_conv_cols; jc++){
                    j = jc + d_common.mask_conv_joffset;
                    jp1 = j + 1;
                    ja1 = (d_common.mask_cols < jp1) ? (jp1 - d_common.mask_cols) : 1;
                    ja2 = (d_common.tMask_cols < j) ? d_common.tMask_cols : j;
                    i = ic + d_common.mask_conv_ioffset;
                    ip1 = i + 1;
                    ia1 = (d_common.mask_rows < ip1) ? (ip1 - d_common.mask_rows) : 1;
                    ia2 = (d_common.tMask_rows < i) ? d_common.tMask_rows : i;
                    s = 0;
                    for(ja = ja1; ja <= ja2; ja++){
                        jb = jp1 - ja;
                        for(ia = ia1; ia <= ia2; ia++){
                            ib = ip1 - ia;
                            s += d_unique.d_tMask[d_common.tMask_rows*(ja-1)+ia-1];
                        }
                    }
                    d_unique.d_mask_conv[(jc-1)*d_common.mask_conv_rows+(ic-1)] = d_unique.d_in2_sqr_sub2[(jc-1)*d_common.mask_conv_rows+(ic-1)] * s;
                }
            }

            #pragma omp barrier

            // Find max value and coordinate
            fp local_max_val = 0;
            int local_max_coo = 0;

            #pragma omp for schedule(static) reduction(max:local_max_val)
            for(i = 0; i < d_common.mask_conv_elem; i++){
                if (d_unique.d_mask_conv[i] > local_max_val){
                    local_max_val = d_unique.d_mask_conv[i];
                    local_max_coo = i;
                }
            }

            #pragma omp critical
            {
                if(local_max_val > fin_max_val){
                    fin_max_val = local_max_val;
                    fin_max_coo = local_max_coo;
                }
            }

            #pragma omp barrier

            #pragma omp single
            {
                largest_row = (fin_max_coo + 1) % d_common.mask_conv_rows - 1;
                largest_col = (fin_max_coo + 1) / d_common.mask_conv_rows;
                if((fin_max_coo + 1) % d_common.mask_conv_rows == 0){
                    largest_row = d_common.mask_conv_rows - 1;
                    largest_col = largest_col - 1;
                }

                largest_row += 1;
                largest_col += 1;
                offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
                offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
                pointer = d_unique.point_no * d_common.no_frames + d_common.frame_no;
                d_unique.d_tRowLoc[pointer] = d_unique.d_Row[d_unique.point_no] + offset_row;
                d_unique.d_tColLoc[pointer] = d_unique.d_Col[d_unique.point_no] + offset_col;
            }
        }

        if(d_common.frame_no != 0 && (d_common.frame_no) % 10 == 0){
            loc_pointer = d_unique.point_no * d_common.no_frames + d_common.frame_no;
            d_unique.d_Row[d_unique.point_no] = d_unique.d_tRowLoc[loc_pointer];
            d_unique.d_Col[d_unique.point_no] = d_unique.d_tColLoc[loc_pointer];

            d_in = &d_unique.d_T[d_unique.in_pointer];

            #pragma omp for schedule(static)
            for(ei_new = 0; ei_new < d_common.in_elem; ei_new++){
                row = (ei_new+1) % d_common.in_rows - 1;
                col = (ei_new+1) / d_common.in_rows;
                if((ei_new+1) % d_common.in_rows == 0){
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }

                ori_row = d_unique.d_Row[d_unique.point_no] - 25 + row - 1;
                ori_col = d_unique.d_Col[d_unique.point_no] - 25 + col - 1;
                ori_pointer = ori_col * d_common.frame_rows + ori_row;

                d_in[ei_new] = d_common.alpha * d_in[ei_new] + (1.00 - d_common.alpha) * d_common.d_frame[ori_pointer];
            }
        }
    }
}
